INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-c5fb3965-moex-00061', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '關於行政執行之拘提及管收，下列敘述何者正確？', '["義務人或其他依法得管收之人有懷胎6月以上或生產後3月未滿者，不 得管收", "自管收之日起算，管收期限不得逾2個月", "法院為拘提之裁定後，應將拘票交由司法警察機關派司法警察執行拘提", "行政執行處應隨時提詢被管收人，每月不得少於3次"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00062', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '行政執行機關就公法上金錢義務人之財產進行強制執行，義務人認為執行 名義並未合法送達，執行行為違反法定程序，其應採何種權利救濟手段？', '["提起訴願", "聲請假處分", "聲明異議", "聲請定暫時狀態"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00063', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '依行政程序法規定，關於送達之敘述，下列何者正確？', '["內容對人民權利義務有重大影響之文書，應由行政機關之承辦人員自行 為送達", "應受送達人之法定代理人有2人以上時，應同時向所有法定代理人為送達", "由郵政機關為送達者，原則上應以一般郵遞方式為之，並以郵務人員為 送達人", "行政機關交由郵政機關為送達者，不得於星期日或其他休息日，或日沒 後為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00064', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '關於行政程序法規定之適用，下列敘述何者正確？', '["司法機關之行政行為不適用行政程序法之實體規定", "犯罪矯正機關為達收容目的所為之行為適用行政程序法之實體規定", "公務員身分產生之公法上財產請求權不適用行政程序法之規定", "行政機關就私權爭執所為之行政裁決適用行政程序法之程序規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00065', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '依行政程序法，關於非書面行政處分，下列敘述何者錯誤？', '["法律未規定何種行政處分應以書面為之時，處分機關有形式選擇自由", "處分機關作成非書面行政處分時，應以適當方法通知相對人、已知之利 害關係人或使其知悉", "處分機關以言詞作成處分時，如相對人有正當理由，可要求處分機關作 成書面", "因相對人要求，處分機關將言詞作成之處分作成書面後，該處分之效力 自書面送達後之次日發生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00066', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '有關受疫情影響企業之紓困申請等事項，主管機關經濟部公告將前述事項 之決定權限交由財團法人工業技術研究院行使，企業如對該院之決定不服 提起訴願，下列何者為訴願管轄機關？', '["行政院", "經濟部", "法務部", "衛生福利部"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00067', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '下列何者不具有訴願代理人之資格？', '["與訴願人有親屬關係者", "因業務或職務關係為訴願人之代理人者", "具有該訴願事件之專業知識者", "承辦訴願案件之公務員"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00068', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '關於訴願法制，下列敘述何者錯誤？', '["訴願決定確定後，有拘束各關係機關之效力", "行政執行因義務人對原行政處分不服提起訴願而停止", "原行政處分經撤銷，原行政處分機關須重為處分者，應依訴願決定意旨 為之", "經聽證程序作成之行政處分，其救濟程序免除訴願及其先行程序"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00069', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '人民因行政機關怠為處分而提起訴願，受理訴願機關應如何決定？', '["訴願有理由時，應自行核定處分", "命應作為之機關為確認之處分", "訴願有理由時，撤銷另為適法之處分", "應作為之機關已為行政處分者，應認訴願為無理由，以決定駁回之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00070', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '有關行政訴訟程序之停止，下列敘述何者正確？', '["行政法院對受理事件所適用之法律，確信有牴觸憲法之疑義時，應停止 訴訟程序，聲請憲法法庭判決", "當事人不得以合意停止訴訟程序，但於公益之維護有礙者，不在此限", "行政法院就其受理訴訟之權限，與普通法院確定裁判之見解有異時，應 以裁定停止訴訟程序，並聲請憲法法庭判決", "訴訟程序當然或裁定停止期間，行政法院及當事人仍得為關於本案之訴 訟行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
